const entry = $json.body?.entry?.[0];
if (!entry) return [];
const changes = entry.changes?.[0]?.value;
if (!changes || !changes.messages) return [];
function toE164(raw) { const s = String(raw || ''); const d = s.replace(/\D/g, ''); return d ? ('+' + d) : s; }
function formatTimestampEuropeRome(epochSeconds) {
  const d = new Date(epochSeconds * 1000);
  const fmt = new Intl.DateTimeFormat('sv-SE', { timeZone: 'Europe/Rome', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false });
  const parts = fmt.formatToParts(d);
  const get = (type) => { const found = parts.find(p => p.type === type); return found && found.value ? found.value : '00'; };
  return get('year') + '-' + get('month') + '-' + get('day') + ' ' + get('hour') + ':' + get('minute') + ':' + get('second');
}
return changes.messages.map(m => {
  const fromE164 = toE164(m.from);
  const toE164Num = toE164(changes.metadata?.display_phone_number || null);
  const text = m.text?.body || m.image?.caption || m.audio?.caption || m.document?.caption || null;
  const ts = formatTimestampEuropeRome(Number(m.timestamp || 0));
  return { json: { wa_id: m.id, from_phone: fromE164, to_phone: toE164Num, direction: 'incoming', message: text, timestamp: ts } };
});

const item = $json;
const msg = item.message;
return [{ json: { wa_id: item.wa_id, from_phone: item.from_phone, to_phone: item.to_phone, direction: 'incoming', message: msg, timestamp: item.timestamp } }];
